import { useState } from "react";
import { useLocation, useNavigate, useParams } from "react-router-dom";
import "../EmployeeDetails/EmployeeDetails.css";

function LeaveApply() {
  const navigate = useNavigate();
  const { id } = useParams();
  const location = useLocation();

  const loggedInUser = JSON.parse(localStorage.getItem("loggedInUser"));

  const [fromDate, setFromDate] = useState("");
  const [toDate, setToDate] = useState("");
  const [reason, setReason] = useState("");

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!fromDate || !toDate || !reason.trim()) {
      alert("Please fill all fields");
      return;
    }

    const leaveRequests =
      JSON.parse(localStorage.getItem("leaveRequests")) || [];

    const newLeave = {
      id: Date.now().toString(),
      empId: id,
      empEmail: loggedInUser?.email,
      empName: loggedInUser?.email.split("@")[0],
      fromDate,
      toDate,
      reason,
      status: "Pending"
    };

    leaveRequests.push(newLeave);
    localStorage.setItem("leaveRequests", JSON.stringify(leaveRequests));

    alert("Leave Applied Successfully");
    navigate("/dashboard/employee-details");
  };

  return (
    <div className="employee-page">
      <h2 className="employee-title">Apply Leave</h2>

      <form className="employee-form" onSubmit={handleSubmit}>
        <div className="form-row">
          <label>From Date</label>
          <input
            type="date"
            value={fromDate}
            onChange={(e) => setFromDate(e.target.value)}
          />
        </div>

        <div className="form-row">
          <label>To Date</label>
          <input
            type="date"
            value={toDate}
            onChange={(e) => setToDate(e.target.value)}
          />
        </div>

        <div className="form-row">
          <label>Reason</label>
          <textarea
            value={reason}
            onChange={(e) => setReason(e.target.value)}
            placeholder="Enter leave reason"
          ></textarea>
        </div>

        <button className="add-btn" type="submit">
          Submit Leave
        </button>

        <button
          type="button"
          className="edit"
          onClick={() => navigate("/dashboard/employee-details")}
          style={{ marginLeft: "10px" }}
        >
          Cancel
        </button>
      </form>
    </div>
  );
}

export default LeaveApply;
